const P = {bg:"#151210",pn:"#1e1a16",cd:"#252118",ca:"#2e2820",bd:"#3a3228",bh:"#c4873b",tx:"#e8dcc8",dm:"#9c8e78",ac:"#c4873b",br2:"#e5a44e",gr:"#4a7a3a",gb:"rgba(74,122,58,0.12)",sf:"#f0c040",rd:"#c44a3b"};

function fmt(n) { return n.toLocaleString(); }

function TierIcon({tier, size=40}) {
  const tiers = {wood:{c:"#8B6914",l:"WOOD",b:"#5C4A1E"},stone:{c:"#9E9E9E",l:"STONE",b:"#616161"},metal:{c:"#B0BEC5",l:"METAL",b:"#546E7A"},armored:{c:"#FFD54F",l:"HQM",b:"#6D5B00"}};
  const t = tiers[tier]||tiers.stone;
  return <div style={{width:size,height:size,borderRadius:4,background:t.b,border:`2px solid ${t.c}`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><span style={{fontSize:size<30?6:8,fontWeight:800,color:t.c}}>{t.l}</span></div>;
}

function Ico({src, size=36}) {
  return <img src={src} alt="" style={{width:size,height:size,objectFit:"contain",filter:"drop-shadow(0 1px 3px rgba(0,0,0,0.5))",flexShrink:0}} onError={e=>{e.target.style.opacity="0.3"}} />;
}

function ItemOrTier({item, size=40}) {
  return item.tier ? <TierIcon tier={item.tier} size={size}/> : item.icon ? <Ico src={item.icon} size={size}/> : null;
}

function QtyCtrl({value, onChange}) {
  return (
    <div style={{display:"flex",alignItems:"center",background:P.bg,borderRadius:4,border:`1px solid ${P.bd}`}}>
      <button style={{width:32,height:32,background:"transparent",border:"none",color:P.ac,fontSize:18,cursor:"pointer",fontFamily:"inherit",fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center"}} onClick={()=>onChange(Math.max(0,value-1))}>-</button>
      <span style={{width:34,textAlign:"center",fontSize:14,fontWeight:700,color:P.tx,borderLeft:`1px solid ${P.bd}`,borderRight:`1px solid ${P.bd}`,lineHeight:"32px"}}>{value}</span>
      <button style={{width:32,height:32,background:"transparent",border:"none",color:P.ac,fontSize:18,cursor:"pointer",fontFamily:"inherit",fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center"}} onClick={()=>onChange(value+1)}>+</button>
    </div>
  );
}

function Card({item, qty, onQty}) {
  const a = qty > 0;
  const cheapest = (() => {
    const c = {c4:item.c4*2200,rocket:item.rocket*1400,satchel:item.satchel*480,expAmmo:item.expAmmo*25};
    return Object.entries(c).reduce((a,b)=>a[1]<=b[1]?a:b)[0];
  })();
  return (
    <div style={{background:a?P.ca:P.cd,border:`1px solid ${a?P.bh:P.bd}`,borderRadius:6,padding:"10px 14px"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <ItemOrTier item={item} size={40}/>
          <div>
            <div style={{fontSize:13,fontWeight:700,color:P.tx}}>{item.name}</div>
            <div style={{fontSize:10,color:P.dm}}>{fmt(item.hp)} HP</div>
          </div>
        </div>
        <QtyCtrl value={qty} onChange={onQty}/>
      </div>
      {a && <div style={{marginTop:8,paddingTop:8,borderTop:`1px solid ${P.bd}`,display:"flex",flexDirection:"column",gap:3}}>
        {Object.entries(METHODS).map(([k,m]) => {
          const c = item[k]*qty;
          const su = c * m.perUnit.sulfur;
          const best = k === cheapest;
          return <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"4px 8px",borderRadius:3,fontSize:12,...(best?{background:P.gb,border:"1px solid rgba(74,122,58,0.25)"}:{})}}>
            <div style={{display:"flex",alignItems:"center",gap:6,color:P.dm,minWidth:120}}><Ico src={m.icon} size={20}/><span>{m.label}</span></div>
            <span style={{fontWeight:700,color:P.tx,minWidth:55,textAlign:"right"}}>{"\u00d7"}{fmt(c)}</span>
            <span style={{color:P.sf,fontWeight:600,minWidth:100,textAlign:"right",display:"flex",alignItems:"center",justifyContent:"flex-end",gap:6}}>
              {fmt(su)} S{best && <span style={{fontSize:9,fontWeight:800,background:P.gr,color:"#fff",padding:"1px 5px",borderRadius:2}}>BEST</span>}
            </span>
          </div>;
        })}
      </div>}
    </div>
  );
}

// ── Quick Calc Page ──
function QuickCalcPage({quickQty, onQuickQty, selectedMethod, onSelectMethod}) {
  // Calculate totals from quick qty
  const totals = useMemo(() => {
    const res = {};
    const keys = ["sulfur","charcoal","metal","cloth","techTrash","lowGrade","pipe","rope","explosives","gunpowder","beancan"];
    keys.forEach(k => { res[k] = 0; });
    Object.entries(quickQty).forEach(([mk, cnt]) => {
      if (cnt > 0 && METHODS[mk]) {
        keys.forEach(k => { res[k] += cnt * METHODS[mk].perUnit[k]; });
      }
    });
    res.totalSulfur = res.sulfur;
    return res;
  }, [quickQty]);

  const hasAny = Object.values(quickQty).some(v => v > 0);

  return (
    <div style={{maxWidth:500,margin:"0 auto"}}>
      <h3 style={{fontSize:10,fontWeight:700,letterSpacing:"2px",color:P.dm,margin:"0 0 10px",textTransform:"uppercase"}}>How many explosives?</h3>
      {Object.entries(METHODS).map(([k,m]) => {
        const cnt = quickQty[k] || 0;
        const a = cnt > 0;
        return <div key={k} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:a?P.ca:P.cd,border:`1px solid ${a?P.bh:P.bd}`,borderRadius:6,marginBottom:5}}>
          <Ico src={m.icon} size={36}/>
          <div style={{flex:1}}>
            <div style={{fontSize:13,fontWeight:700,color:P.tx}}>{m.label}</div>
            <div style={{fontSize:10,color:P.dm}}>{m.recipe}</div>
          </div>
          <QtyCtrl value={cnt} onChange={v => onQuickQty(k, v)}/>
        </div>;
      })}

      {hasAny && <>
        <h3 style={{fontSize:10,fontWeight:700,letterSpacing:"2px",color:P.dm,margin:"16px 0 8px",textTransform:"uppercase"}}>Total resources needed</h3>

        {totals.explosives > 0 && <ResRow icon={ICONS.explosives} label="Explosives" amount={totals.explosives}/>}
        {totals.beancan > 0 && <ResRow icon={ICONS.beancan} label="Beancan grenades" amount={totals.beancan}/>}
        {totals.gunpowder > 0 && <ResRow icon={ICONS.gunpowder} label="Gunpowder" amount={totals.gunpowder}/>}

        <div style={{height:1,background:P.bd,margin:"8px 0"}}/>

        <ResRow icon={ICONS.sulfur} label="Sulfur" amount={totals.sulfur} highlight/>
        <ResRow icon={ICONS.charcoal} label="Charcoal" amount={totals.charcoal}/>
        <ResRow icon={ICONS.metal} label="Metal fragments" amount={totals.metal}/>
        {totals.lowGrade > 0 && <ResRow icon={ICONS.lowGrade} label="Low grade fuel" amount={totals.lowGrade}/>}
        {totals.cloth > 0 && <ResRow icon={ICONS.cloth} label="Cloth" amount={totals.cloth}/>}
        {totals.techTrash > 0 && <ResRow icon={ICONS.techTrash} label="Tech trash" amount={totals.techTrash}/>}
        {totals.pipe > 0 && <ResRow icon={ICONS.pipe} label="Metal pipe" amount={totals.pipe}/>}
        {totals.rope > 0 && <ResRow icon={ICONS.rope} label="Rope" amount={totals.rope}/>}

        <div style={{display:"flex",alignItems:"center",gap:10,background:"rgba(240,192,64,0.06)",border:"1px solid rgba(240,192,64,0.18)",borderRadius:6,padding:10,marginTop:10}}>
          <Ico src={ICONS.sulfurOre} size={28}/>
          <div>
            <div style={{fontSize:16,fontWeight:800,color:P.sf}}>~{fmt(Math.ceil(totals.sulfur/150))} sulfur nodes</div>
            <div style={{fontSize:9,color:P.dm}}>~150 sulfur per node</div>
          </div>
        </div>

        <h3 style={{fontSize:10,fontWeight:700,letterSpacing:"2px",color:P.dm,margin:"14px 0 8px",textTransform:"uppercase"}}>View crafting flow</h3>
        {Object.entries(quickQty).filter(([,v])=>v>0).map(([k]) =>
          <button key={k} onClick={() => onSelectMethod(k)} style={{display:"flex",alignItems:"center",gap:8,width:"100%",padding:"8px 10px",marginBottom:4,background:selectedMethod===k?P.gb:P.cd,border:selectedMethod===k?`2px solid ${P.gr}`:`1px solid ${P.bd}`,borderRadius:6,cursor:"pointer",fontFamily:"inherit"}}>
            <Ico src={METHODS[k].icon} size={24}/>
            <span style={{fontSize:12,fontWeight:600,color:P.tx}}>{METHODS[k].label} {"\u00d7"}{quickQty[k]}</span>
            {selectedMethod===k && <span style={{fontSize:9,fontWeight:800,background:P.gr,color:"#fff",padding:"1px 5px",borderRadius:2,marginLeft:"auto"}}>VIEWING</span>}
          </button>
        )}
      </>}
    </div>
  );
}

function ResRow({icon, label, amount, highlight}) {
  return <div style={{display:"flex",alignItems:"center",gap:10,padding:"6px 10px",background:highlight?"rgba(196,135,59,0.1)":P.cd,border:`1px solid ${highlight?P.ac:P.bd}`,borderRadius:6,marginBottom:3}}>
    <Ico src={icon} size={26}/>
    <div style={{flex:1,fontSize:12,fontWeight:600,color:P.tx}}>{label}</div>
    <div style={{fontSize:14,fontWeight:700,color:highlight?P.sf:P.tx}}>{fmt(amount)}</div>
  </div>;
}

// ── Summary Page ──
function SummaryPage({mT, selectedMethod, onSelectMethod, onClear, hasAny}) {
  if (!hasAny) return <div style={{textAlign:"center",padding:"60px 20px"}}><Ico src={ICONS.satchel} size={56}/><p style={{color:P.dm,fontSize:13,marginTop:12}}>Add structures from the tabs above</p></div>;
  return (
    <div style={{maxWidth:500,margin:"0 auto"}}>
      <h3 style={{fontSize:10,fontWeight:700,letterSpacing:"2px",color:P.dm,margin:"0 0 10px",textTransform:"uppercase"}}>Select method</h3>
      {Object.entries(mT).map(([k,d]) => {
        const m = METHODS[k];
        const active = k === selectedMethod;
        return <button key={k} onClick={()=>onSelectMethod(k)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",width:"100%",padding:"10px 12px",borderRadius:6,marginBottom:5,background:active?P.gb:P.cd,border:active?`2px solid ${P.gr}`:`1px solid ${P.bd}`,cursor:"pointer",fontFamily:"inherit"}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <Ico src={m.icon} size={32}/>
            <div style={{textAlign:"left"}}>
              <div style={{fontSize:13,fontWeight:600,color:P.tx}}>{m.label}</div>
              <div style={{fontSize:11,color:P.dm}}>{"\u00d7"}{fmt(d.count)} needed</div>
            </div>
          </div>
          <div style={{textAlign:"right"}}>
            <div style={{fontSize:16,fontWeight:700,color:active?P.sf:P.tx}}>{fmt(d.sulfur)}</div>
            <div style={{fontSize:10,color:P.dm}}>sulfur</div>
            {active && <span style={{display:"inline-block",fontSize:9,fontWeight:800,background:P.gr,color:"#fff",padding:"2px 6px",borderRadius:2,marginTop:2}}>SELECTED</span>}
          </div>
        </button>;
      })}
      <button style={{width:"100%",padding:10,marginTop:12,background:"transparent",border:`1px solid ${P.rd}`,borderRadius:4,color:P.rd,fontSize:12,fontFamily:"inherit",fontWeight:700,cursor:"pointer"}} onClick={onClear}>Clear All</button>
    </div>
  );
}

// ── SVG Flow Components ──
function FlowNode({x,y,w,h,icon,label,amount,color,borderColor}) {
  const bw=w||130,bh=h||48;
  return <g>
    <rect x={x} y={y} width={bw} height={bh} rx={6} fill={color||"#2a2519"} stroke={borderColor||"#4a3f30"} strokeWidth={1.5}/>
    {icon && <image href={icon} x={x+6} y={y+(bh-24)/2} width={24} height={24}/>}
    <text x={x+(icon?34:bw/2)} y={y+bh/2-7} fill="#e8dcc8" fontSize={10} fontWeight={700} fontFamily="inherit" textAnchor={icon?"start":"middle"}>{label}</text>
    {amount!==undefined && <text x={x+(icon?34:bw/2)} y={y+bh/2+7} fill="#f0c040" fontSize={11} fontWeight={700} fontFamily="inherit" textAnchor={icon?"start":"middle"}>{fmt(amount)}</text>}
  </g>;
}

function FlowArrow({x1,y1,x2,y2,color}) {
  const c=color||"#6b5d44";
  if(Math.abs(y1-y2)<3) {
    return <g>
      <line x1={x1} y1={y1} x2={x2-7} y2={y2} stroke={c} strokeWidth={2}/>
      <polygon points={`${x2},${y2} ${x2-8},${y2-4} ${x2-8},${y2+4}`} fill={c}/>
    </g>;
  }
  const mx = x2-20;
  return <g>
    <polyline points={`${x1},${y1} ${mx},${y1} ${mx},${y2} ${x2-7},${y2}`} fill="none" stroke={c} strokeWidth={2} strokeLinejoin="round"/>
    <polygon points={`${x2},${y2} ${x2-8},${y2-4} ${x2-8},${y2+4}`} fill={c}/>
  </g>;
}

// ── Crafting Page ──
function CraftingPage({mT, selectedMethod, quickMode, quickQty}) {
  const m = METHODS[selectedMethod];
  const count = quickMode ? (quickQty[selectedMethod]||0) : (mT[selectedMethod]?.count||0);
  if (count === 0) return <div style={{textAlign:"center",padding:"60px 20px"}}><Ico src={ICONS.satchel} size={56}/><p style={{color:P.dm,fontSize:13,marginTop:12}}>Add items and select a method first</p></div>;

  const pu = m.perUnit;
  const t = (key) => count * pu[key];

  const hasExp = t("explosives") > 0;
  const hasBean = t("beancan") > 0;
  const hasLGF = t("lowGrade") > 0;

  // Layout
  const nw = 125, nh = 46, gx = 28, gy = 8;
  const cols = [16, 16+nw+gx, 16+(nw+gx)*2, 16+(nw+gx)*3, 16+(nw+gx)*4];
  const lastCol = (hasExp||hasBean) ? cols[4] : cols[3];
  const svgW = lastCol+nw+16;

  // Rows for main path
  const r1=28, r2=r1+nh+gy, r3=r2+nh+gy;
  const rGP = r1 + (nh+gy)/2;

  // Extra raw resources stacked below metal row
  const extraRes = [];
  if (hasLGF) extraRes.push({key:"lowGrade",icon:ICONS.lowGrade,label:"Low grade",amount:t("lowGrade"),color:"#6D5B00"});
  if (t("cloth")>0) extraRes.push({key:"cloth",icon:ICONS.cloth,label:"Cloth",amount:t("cloth"),color:"#8b7355"});
  if (t("techTrash")>0) extraRes.push({key:"techTrash",icon:ICONS.techTrash,label:"Tech trash",amount:t("techTrash"),color:"#40a0c0"});
  if (t("pipe")>0) extraRes.push({key:"pipe",icon:ICONS.pipe,label:"Metal pipe",amount:t("pipe"),color:"#a0a0a0"});
  if (t("rope")>0) extraRes.push({key:"rope",icon:ICONS.rope,label:"Rope",amount:t("rope"),color:"#8b7355"});

  const extraStartY = r3 + nh + gy;
  const rExp = hasBean ? r1 : rGP;
  const rBean = r2 + 8;
  const rFinal = hasBean ? r1 + nh/2 + gy/2 : rGP;

  // Craft column target Y for extra arrows
  const craftCol = (hasExp||hasBean) ? cols[3] : lastCol;
  const craftTargetY = (hasExp) ? rExp + nh/2 : (hasBean ? rBean + nh/2 : rFinal + nh/2);

  const lastRow = extraRes.length > 0 ? extraStartY + (extraRes.length-1)*(nh+gy) + nh : r3 + nh;
  const svgH = Math.max(lastRow + 16, rFinal + nh + 16);

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,padding:"10px 12px",background:"rgba(196,135,59,0.1)",border:`1px solid ${P.ac}`,borderRadius:8}}>
        <Ico src={m.icon} size={36}/>
        <div>
          <div style={{fontSize:16,fontWeight:700,color:P.tx}}>{fmt(count)} {m.label}</div>
          <div style={{fontSize:11,color:P.dm}}>{m.recipe}</div>
        </div>
      </div>

      {/* SVG Flow */}
      <div style={{overflowX:"auto",overflowY:"hidden",margin:"0 -14px",padding:"0 14px 8px"}}>
        <svg width={svgW} height={svgH} viewBox={`0 0 ${svgW} ${svgH}`} style={{fontFamily:"'JetBrains Mono','Fira Code',monospace",display:"block",minWidth:svgW}}>
          {/* Column headers */}
          <text x={cols[0]+nw/2} y={16} fill="#6b5d44" fontSize={8} textAnchor="middle" fontFamily="inherit" letterSpacing="1.5" fontWeight={700}>RAW</text>
          <text x={cols[1]+nw/2} y={16} fill="#6b5d44" fontSize={8} textAnchor="middle" fontFamily="inherit" letterSpacing="1.5" fontWeight={700}>SMELTED</text>
          <text x={cols[2]+nw/2} y={16} fill="#6b5d44" fontSize={8} textAnchor="middle" fontFamily="inherit" letterSpacing="1.5" fontWeight={700}>MIX</text>
          {(hasExp||hasBean) && <text x={cols[3]+nw/2} y={16} fill="#6b5d44" fontSize={8} textAnchor="middle" fontFamily="inherit" letterSpacing="1.5" fontWeight={700}>CRAFT</text>}
          <text x={lastCol+nw/2} y={16} fill="#6b5d44" fontSize={8} textAnchor="middle" fontFamily="inherit" letterSpacing="1.5" fontWeight={700}>FINAL</text>

          {/* Sulfur row */}
          <FlowNode x={cols[0]} y={r1} icon={ICONS.sulfurOre} label="Sulfur ore" amount={t("sulfur")} color="#332a1a" borderColor="#8b6914"/>
          <FlowArrow x1={cols[0]+nw} y1={r1+nh/2} x2={cols[1]} y2={r1+nh/2} color="#8b6914"/>
          <FlowNode x={cols[1]} y={r1} icon={ICONS.sulfur} label="Sulfur" amount={t("sulfur")} color="#33301a" borderColor="#c4873b"/>

          {/* Charcoal row */}
          <FlowNode x={cols[0]} y={r2} icon={ICONS.wood} label="Wood" amount={Math.ceil(t("charcoal")*1.33)} color="#1e2a18" borderColor="#4a7a3a"/>
          <FlowArrow x1={cols[0]+nw} y1={r2+nh/2} x2={cols[1]} y2={r2+nh/2} color="#4a7a3a"/>
          <FlowNode x={cols[1]} y={r2} icon={ICONS.charcoal} label="Charcoal" amount={t("charcoal")} color="#222018" borderColor="#666"/>

          {/* Sulfur + Charcoal -> Gunpowder */}
          <FlowArrow x1={cols[1]+nw} y1={r1+nh/2} x2={cols[2]} y2={rGP+nh/2} color="#c4873b"/>
          <FlowArrow x1={cols[1]+nw} y1={r2+nh/2} x2={cols[2]} y2={rGP+nh/2} color="#666"/>
          {t("gunpowder")>0 && <FlowNode x={cols[2]} y={rGP} icon={ICONS.gunpowder} label="Gunpowder" amount={t("gunpowder")} color="#2a1a18" borderColor="#c44a3b"/>}

          {/* Metal row */}
          {t("metal")>0 && <>
            <FlowNode x={cols[0]} y={r3} icon={ICONS.metalOre} label="Metal ore" amount={t("metal")} color="#1e1e1e" borderColor="#888"/>
            <FlowArrow x1={cols[0]+nw} y1={r3+nh/2} x2={cols[1]} y2={r3+nh/2} color="#888"/>
            <FlowNode x={cols[1]} y={r3} icon={ICONS.metal} label="Metal frags" amount={t("metal")} color="#1e1e1e" borderColor="#aaa"/>
          </>}

          {/* Extra raw resources (LGF, cloth, tech trash, pipe, rope) */}
          {extraRes.map((er, idx) => {
            const ey = extraStartY + idx * (nh + gy);
            return <g key={er.key}>
              <FlowNode x={cols[0]} y={ey} icon={er.icon} label={er.label} amount={er.amount} color="#1e1e1e" borderColor={er.color}/>
              <FlowArrow x1={cols[0]+nw} y1={ey+nh/2} x2={craftCol} y2={craftTargetY} color={er.color}/>
            </g>;
          })}

          {/* Metal -> Explosives/Craft */}
          {hasExp && <>
            <FlowArrow x1={cols[2]+nw} y1={rGP+nh/2} x2={cols[3]} y2={rExp+nh/2} color="#c44a3b"/>
            {t("metal")>0 && <FlowArrow x1={cols[1]+nw} y1={r3+nh/2} x2={cols[3]} y2={rExp+nh/2} color="#aaa"/>}
            <FlowNode x={cols[3]} y={rExp} icon={ICONS.explosives} label="Explosives" amount={t("explosives")} color="#2a1818" borderColor="#e24b4a"/>
            <FlowArrow x1={cols[3]+nw} y1={rExp+nh/2} x2={cols[4]} y2={rFinal+nh/2} color="#e24b4a"/>
          </>}

          {hasBean && <>
            <FlowArrow x1={cols[2]+nw} y1={rGP+nh/2} x2={cols[3]} y2={rBean+nh/2} color="#d4537e"/>
            <FlowNode x={cols[3]} y={rBean} icon={ICONS.beancan} label="Beancans" amount={t("beancan")} color="#2a1820" borderColor="#d4537e"/>
            <FlowArrow x1={cols[3]+nw} y1={rBean+nh/2} x2={cols[4]} y2={rFinal+nh/2} color="#d4537e"/>
          </>}

          {!hasExp && !hasBean && <>
            <FlowArrow x1={cols[2]+nw} y1={rGP+nh/2} x2={cols[3]} y2={rFinal+nh/2} color="#c4873b"/>
            {t("metal")>0 && <FlowArrow x1={cols[1]+nw} y1={r3+nh/2} x2={cols[3]} y2={rFinal+nh/2} color="#aaa"/>}
          </>}

          {/* Final item */}
          <FlowNode x={lastCol} y={rFinal} w={nw} icon={m.icon} label={m.label} amount={count} color="#2a2210" borderColor="#e5a44e"/>
        </svg>
      </div>

      {/* Ingredient list */}
      <h3 style={{fontSize:9,fontWeight:700,letterSpacing:"2px",color:P.dm,margin:"8px 0 6px",textTransform:"uppercase"}}>All ingredients</h3>
      <ResRow icon={ICONS.sulfur} label="Sulfur" amount={t("sulfur")} highlight/>
      <ResRow icon={ICONS.charcoal} label="Charcoal" amount={t("charcoal")}/>
      <ResRow icon={ICONS.metal} label="Metal fragments" amount={t("metal")}/>
      {t("lowGrade")>0 && <ResRow icon={ICONS.lowGrade} label="Low grade fuel" amount={t("lowGrade")}/>}
      {t("cloth")>0 && <ResRow icon={ICONS.cloth} label="Cloth" amount={t("cloth")}/>}
      {t("techTrash")>0 && <ResRow icon={ICONS.techTrash} label="Tech trash" amount={t("techTrash")}/>}
      {t("pipe")>0 && <ResRow icon={ICONS.pipe} label="Metal pipe" amount={t("pipe")}/>}
      {t("rope")>0 && <ResRow icon={ICONS.rope} label="Rope" amount={t("rope")}/>}

      {/* Farming */}
      <div style={{display:"flex",gap:6,marginTop:8}}>
        <div style={{flex:1,display:"flex",alignItems:"center",gap:8,background:"rgba(240,192,64,0.06)",border:"1px solid rgba(240,192,64,0.18)",borderRadius:6,padding:10}}>
          <Ico src={ICONS.sulfurOre} size={26}/>
          <div>
            <div style={{fontSize:15,fontWeight:800,color:P.sf}}>~{fmt(Math.ceil(t("sulfur")/150))}</div>
            <div style={{fontSize:9,color:P.dm}}>sulfur nodes</div>
          </div>
        </div>
        <div style={{flex:1,display:"flex",alignItems:"center",gap:8,background:"rgba(74,122,58,0.06)",border:"1px solid rgba(74,122,58,0.18)",borderRadius:6,padding:10}}>
          <Ico src={ICONS.wood} size={26}/>
          <div>
            <div style={{fontSize:15,fontWeight:800,color:"#8bbb5a"}}>~{fmt(Math.ceil(t("charcoal")*1.33))}</div>
            <div style={{fontSize:9,color:P.dm}}>wood needed</div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Main ──
export default function RustRaidCalc() {
  const [page, setPage] = useState("doors");
  const [qty, setQty] = useState({});
  const [selectedMethod, setSelectedMethod] = useState("c4");
  const [quickQty, setQuickQty] = useState({c4:0,rocket:0,satchel:0,expAmmo:0});

  const q = (c,i) => qty[`${c}-${i}`] || 0;
  const sq = (c,i,v) => setQty(p => ({...p, [`${c}-${i}`]: v}));
  const sqq = (k,v) => setQuickQty(p => ({...p, [k]: v}));

  const mT = useMemo(() => {
    const m = {};
    Object.keys(METHODS).forEach(k => {
      let te = 0, ts = 0;
      Object.entries(STRUCTURES).forEach(([ck,cv]) => cv.items.forEach((it,i) => {
        const n = q(ck,i);
        if (n > 0) { const c = it[k]*n; te += c; ts += c * METHODS[k].perUnit.sulfur; }
      }));
      m[k] = {count: te, sulfur: ts};
    });
    return m;
  }, [qty]);

  const hasStructures = Object.values(mT).some(d => d.count > 0);
  const hasQuick = Object.values(quickQty).some(v => v > 0);
  const cc = (ck) => STRUCTURES[ck] ? STRUCTURES[ck].items.reduce((s,_,i) => s + (q(ck,i)>0?1:0), 0) : 0;
  const totalActive = Object.keys(STRUCTURES).reduce((s,k) => s + cc(k), 0);

  // Determine what the crafting page should show
  const quickMode = page === "crafting" && hasQuick && !hasStructures;
  const craftCount = quickMode ? (quickQty[selectedMethod]||0) : (mT[selectedMethod]?.count||0);

  return (
    <div style={{fontFamily:"'JetBrains Mono','Fira Code','Source Code Pro',monospace",background:P.bg,color:P.tx,minHeight:"100vh",display:"flex",flexDirection:"column"}}>
      <div style={{background:`linear-gradient(135deg,${P.pn} 0%,#2a1f12 100%)`,borderBottom:`2px solid ${P.ac}`,flexShrink:0}}>
        <div style={{padding:"14px 16px",display:"flex",alignItems:"center",gap:12}}>
          <Ico src={ICONS.c4} size={38}/>
          <div style={{flex:1}}><h1 style={{margin:0,fontSize:18,fontWeight:800,letterSpacing:"3px",color:P.br2,textTransform:"uppercase"}}>RUST RAID CALC</h1></div>
        </div>
      </div>

      <div style={{display:"flex",overflowX:"auto",gap:0,background:P.pn,borderBottom:`1px solid ${P.bd}`,flexShrink:0}}>
        {PAGES.map(p => {
          const active = page === p.id;
          const count = STRUCTURES[p.id] ? cc(p.id) : 0;
          const hasData = (p.id==="summary" && hasStructures) || (p.id==="crafting" && (hasStructures||hasQuick)) || (p.id==="quick" && hasQuick);
          return <button key={p.id} onClick={() => setPage(p.id)} style={{display:"flex",alignItems:"center",gap:5,padding:"10px 14px",background:active?P.ca:"transparent",color:active?P.br2:P.dm,fontSize:11,fontFamily:"inherit",fontWeight:600,cursor:"pointer",border:"none",borderBottom:active?`2px solid ${P.ac}`:"2px solid transparent",whiteSpace:"nowrap",flexShrink:0}}>
            {p.icon ? <Ico src={p.icon} size={18}/> : <TierIcon tier={p.tier} size={18}/>}
            <span>{p.label}</span>
            {count > 0 && <span style={{fontSize:8,fontWeight:800,background:P.ac,color:"#000",borderRadius:8,padding:"1px 5px"}}>{count}</span>}
            {hasData && count===0 && <span style={{width:6,height:6,borderRadius:3,background:P.sf,display:"inline-block",marginLeft:2}}/>}
          </button>;
        })}
      </div>

      <div style={{flex:1,padding:14,overflowY:"auto"}}>
        {STRUCTURES[page] && <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {STRUCTURES[page].items.map((it,i) => <Card key={i} item={it} qty={q(page,i)} onQty={v => sq(page,i,v)}/>)}
        </div>}
        {page === "quick" && <QuickCalcPage quickQty={quickQty} onQuickQty={sqq} selectedMethod={selectedMethod} onSelectMethod={s => { setSelectedMethod(s); setPage("crafting"); }}/>}
        {page === "summary" && <SummaryPage mT={mT} selectedMethod={selectedMethod} onSelectMethod={setSelectedMethod} onClear={() => setQty({})} hasAny={hasStructures}/>}
        {page === "crafting" && <CraftingPage mT={mT} selectedMethod={selectedMethod} quickMode={quickMode} quickQty={quickQty}/>}
      </div>

      <div style={{textAlign:"center",padding:8,fontSize:9,color:P.dm,borderTop:`1px solid ${P.bd}`,flexShrink:0}}>Vanilla Rust (Apr 2026) {"\u00b7"} Explo ammo assumes AK/LR</div>
    </div>
  );
}
